args.sparql:
PREFIX rdfs: http://www.w3.org/2000/01/rdf-schema#
SELECT DISTINCT ?person ?personLabel WHERE {
  ?person p:P3446 [
    ps:P3446 ?count ;
    pq:P3470 wd:Q1807
  ] .
  ?person rdfs:label ?personLabel .
  FILTER (LANG(?personLabel) = 'en')
}
ORDER BY DESC(?count)
LIMIT 1

